import org.apache.spark.sql.{SparkSession, DataFrame}
import org.apache.spark.sql.functions._
import java.util.UUID
import scala.util.{Try, Success, Failure}

case class QueryRequest(sql: String, requestId: String = UUID.randomUUID().toString)
case class QueryResult(requestId: String, data: Option[DataFrame], error: Option[String])

class SecureSparkQueryEngine {
  private val spark: SparkSession = SparkSession.builder()
    .appName("SecureSparkAnalytics")
    .getOrCreate()
  
  private val ALLOWED_TABLES = Set("users", "orders", "products", "analytics")
  private val ALLOWED_FUNCTIONS = Set("count", "sum", "avg", "min", "max", "year", "month", "day")
  private val ALLOWED_OPERATORS = Set("=", "!=", "<", ">", "<=", ">=", "LIKE", "IN")
  
  def executeQuery(queryRequest: QueryRequest): QueryResult = {
    Try {
      val sanitizedQuery = sanitizeQuery(queryRequest.sql)
      val result = spark.sql(sanitizedQuery)
      QueryResult(queryRequest.requestId, Some(result), None)
    } match {
      case Success(result) => result
      case Failure(exception) => 
        QueryResult(queryRequest.requestId, None, Some(exception.getMessage))
    }
  }
  
  private def sanitizeQuery(sql: String): String = {
    val cleanSql = sql.trim
    val upperSql = cleanSql.toUpperCase
    
    // Check for forbidden patterns
    if (upperSql.contains("DROP") || upperSql.contains("DELETE") || 
        upperSql.contains("INSERT") || upperSql.contains("UPDATE") ||
        upperSql.contains("CREATE") || upperSql.contains("ALTER") ||
        upperSql.contains("TRUNCATE") || upperSql.contains("EXEC") ||
        upperSql.contains("UNION") || upperSql.contains("--") ||
        upperSql.contains("/*") || upperSql.contains("*/")) {
      throw new SecurityException("Forbidden SQL operations detected")
    }
    
    // Validate table names and structure
    validateQueryStructure(cleanSql)
    
    cleanSql
  }
  
  private def validateQueryStructure(sql: String): Unit = {
    val upperSql = sql.toUpperCase
    val tablePattern = """FROM\s+(\w+)""".r
    val tables = tablePattern.findAllIn(upperSql).map(_.group(1)).toSet
    
    // Validate that only allowed tables are used
    if (tables.exists(table => !ALLOWED_TABLES.contains(table))) {
      throw new SecurityException("Unauthorized table access attempted")
    }
    
    // Validate function usage
    val functionPattern = """(\w+)\s*\(""".r
    val functions = functionPattern.findAllIn(upperSql).map(_.group(1)).toSet
    
    if (functions.exists(func => !ALLOWED_FUNCTIONS.contains(func))) {
      throw new SecurityException("Unauthorized function usage")
    }
  }
  
  def executeQueryWithParameters(queryRequest: QueryRequest, parameters: Map[String, Any]): QueryResult = {
    Try {
      val sanitizedQuery = sanitizeQuery(queryRequest.sql)
      val finalQuery = applyParameters(sanitizedQuery, parameters)
      val result = spark.sql(finalQuery)
      QueryResult(queryRequest.requestId, Some(result), None)
    } match {
      case Success(result) => result
      case Failure(exception) => 
        QueryResult(queryRequest.requestId, None, Some(exception.getMessage))
    }
  }
  
  private def applyParameters(query: String, parameters: Map[String, Any]): String = {
    var finalQuery = query
    parameters.foreach { case (key, value) =>
      val escapedValue = escapeValue(value)
      finalQuery = finalQuery.replace(s":$key", escapedValue)
    }
    finalQuery
  }
  
  private def escapeValue(value: Any): String = {
    value match {
      case s: String => s"'${s.replace("'", "''")}'"
      case n: Number => n.toString
      case b: Boolean => if (b) "true" else "false"
      case null => "NULL"
      case _ => value.toString
    }
  }
  
  def close(): Unit = {
    spark.stop()
  }
}

